worked_example.final_code:
import java.util.*;
import java.util.stream.*;

class Stock {
    private String symbol, sector;
    private double price, dailyChange;
    Stock(String sym, String sec, double p, double dc) {
        symbol=sym; sector=sec; price=p; dailyChange=dc;
    }
    public String getSymbol()     { return symbol; }
    public String getSector()     { return sector; }
    public double getPrice()      { return price; }
    public double getDailyChange(){ return dailyChange; }
}

public class WatchlistAnalysis {
    public static void main(String[] args) {
        List<Stock> watchlist = Arrays.asList(
            new Stock("RELIANCE", "Energy",  2450, +1.2),
            new Stock("TCS",      "IT",      3890, +4.1),
            new Stock("INFY",     "IT",      1560, -3.8),
            new Stock("HDFC",     "Finance", 1678, +0.5),
            new Stock("WIPRO",    "IT",       412, +5.2),
            new Stock("ZOMATO",   "Consumer", 184, -1.3)
        );

        // Query 1: Gainers
        List<String> gainers = watchlist.stream()
            .filter(s -> s.getDailyChange() > 0)
            .sorted((a, b) -> Double.compare(b.getDailyChange(), a.getDailyChange()))
            .map(Stock::getSymbol)
            .collect(Collectors.toList());
        System.out.println("Gainers: " + gainers);

        // Query 2: IT avg price
        OptionalDouble avg = watchlist.stream()
            .filter(s -> s.getSector().equals("IT"))
            .mapToDouble(Stock::getPrice)
            .average();
        System.out.printf("IT avg price: ₹%.2f%n", avg.orElse(0));

        // Query 3: Big mover?
        boolean bigMover = watchlist.stream()
            .anyMatch(s -> Math.abs(s.getDailyChange()) > 5);
        System.out.println("Any > 5% change: " + bigMover);

        // Query 4: Unique sectors
        List<String> sectors = watchlist.stream()
            .map(Stock::getSector)
            .distinct()
            .sorted()
            .collect(Collectors.toList());
        System.out.println("Sectors: " + sectors);

        // Query 5: Top 3 most expensive
        List<String> top3 = watchlist.stream()
            .sorted((a, b) -> Double.compare(b.getPrice(), a.getPrice()))
            .limit(3)
            .map(Stock::getSymbol)
            .collect(Collectors.toList());
        System.out.println("Top 3 expensive: " + top3);
    }
}

